import{_ as o,o as a,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Via File Upload","description":"","frontmatter":{"title":"Via File Upload","slug":"cost-data-via-file-upload"},"headers":[],"relativePath":"marketer-hub/cost-data-via-file-upload.md","filePath":"marketer-hub/cost-data-via-file-upload.md"}'),i={name:"marketer-hub/cost-data-via-file-upload.md"};function d(l,e,c,n,s,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>If you would like to upload your ad partner cost data using the Branch Dashboard, you can do so using ROI Hub&#39;s <strong>File Upload</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import?section=file-upload" target="_blank" rel="noreferrer">view</a>.</p><p>Uploading this data will pipe it to your Branch Dashboard reports, where you can analyze campaign performance across multiple ad partners in one place.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to start tracking cost data, you first need to:</p><ol><li><p>Create a <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enable our <a href="./packaging.html#performance-pro-tier">Performance product</a> for your Branch account.</p><ol><li>Contact your Branch account manager or our <a href="https://www.branch.io/contact-sales" target="_blank" rel="noreferrer">sales team</a> to get started.</li></ol></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-basic-integration.html">iOS</a> | <a href="./android-basic-integration.html">Android</a>).</p></li></ol><h2 id="file-templates" tabindex="-1">File Templates <a class="header-anchor" href="#file-templates" aria-label="Permalink to &quot;File Templates&quot;">​</a></h2><p>Before you can upload a file containing cost data, you first need to <a href="./templates-for-cost-data.html#create-new-file-template">create a file template</a> for the ad partner associated with data.</p><p>File templates help map your custom cost data fields to standard Branch fields.</p><h2 id="file-requirements" tabindex="-1">File Requirements <a class="header-anchor" href="#file-requirements" aria-label="Permalink to &quot;File Requirements&quot;">​</a></h2><ul><li><p>Your file can have any name, but it must be a CSV file and end with the <code>.csv</code> file extension.</p></li><li><p>For every row in your CSV, you <strong>must fill out the following columns</strong>:</p><ul><li><code>date</code> (use the format YYYY-MM-DD)</li><li><code>campaign_name</code></li><li><code>cost</code> (enter cost data in the format <code>1234.56</code> - do not include any currency symbols or commas)</li></ul></li><li><p><strong>If</strong> you fill out data for the <code>country_code</code> field, you must use the country code with capital letters, i.e. <code>FR</code> or <code>US</code>.</p></li><li><p><strong>If</strong> you fill out data for the <code>os</code> field, you must use one of the following values: <code>IOS</code>, <code>ANDROID</code>, <code>MAC_OS</code>, <code>WINDOWS</code>, <code>WINDOWS_PHONE</code>, <code>AMAZON_FIRE</code>, <code>AMAZON_FIRE_TV</code>, <code>ROKU</code>, <code>SAMSUNG</code>, <code>ANDROID_TV</code>, <code>LG</code>, <code>PANASONIC</code>, <code>TV_OS</code>, <code>CHROMECAST</code>, <code>PLAYSTATION</code>, <code>BADA</code>, <code>BEOS</code>, <code>BLACKBERRY</code>, <code>BSD</code>, <code>CENTOS</code>, <code>CHROMIUM_OS</code>, <code>DEBIAN</code>, <code>DRAGONFLY</code>, <code>FEDORA</code>, <code>FIREFOX_OS</code>, <code>FREEBSD</code>, <code>GENTOO</code>, <code>GNU</code>, <code>JOLI</code>, <code>KUBUNTU</code>, <code>LINUX</code>, <code>MANDRIVA</code>, <code>MEEGO</code>, <code>MINT</code>, <code>NETBSD</code>, <code>NINTENDO</code>, <code>OPENBSD</code>, <code>OS_2</code>, <code>RIM_TABLET_OS</code>, <code>SAILFISH</code>, <code>SLACKWARE</code>, <code>SOLARIS</code>, <code>SUSE</code>, <code>SYMBIAN</code>, <code>TIZEN</code>, <code>UBUNTU</code>, <code>UNIX</code>, <code>ZENWALK</code>, <code>XBOX</code>, <code>WEBOS</code>, <code>OTHER</code>, <code>ROBOTS</code>.</p></li></ul><h2 id="file-upload" tabindex="-1">File Upload <a class="header-anchor" href="#file-upload" aria-label="Permalink to &quot;File Upload&quot;">​</a></h2><p>To upload a file containing cost data:</p><ol><li><p>Navigate to the <strong>Import</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import?section=file-upload" target="_blank" rel="noreferrer">tab</a> of ROI Hub, then click on <strong>File Upload</strong>.</p></li><li><p>You will see the <strong>Upload cost file</strong> view, where you need to fill out:</p><ol><li><p>Ad partner (required)</p><ol><li>You will only be able to select an ad partner if you have <a href="./templates-for-cost-data.html">created a file template associated with it</a>.</li></ol></li><li><p>Default account ID (optional)</p><ol><li>You can find this on the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Ad Partner Settings page</a> for the ad partner.</li><li>This is important if you are uploading data for the same ad partner multiple times, as it might override existing data uploaded.</li></ol></li><li><p>Default currency (required)</p><p><em>[Image: aa0cb33422bc2d91d37a8ad77caa3265ca35270081669c0cda3926a36fdb3212-c93dd7ac0a7b599bd4a212e8a4ad39ac0adfde21be288ab178c308536a08ca7e-Screenshot_2024-10-30_at_2.21.58_PM.png]</em>.png)</p></li></ol></li><li><p>In the <strong>Select cost data file</strong> section, click the <strong>Upload</strong> button and upload your CSV file.</p></li><li><p>At this point, we recommend using the file validation feature to make sure your file is properly formatted before attempting to process it, since that can take several hours. To validate your file&#39;s formatting, click the <strong>Run quick validation</strong> button.<br><em>[Image: 61d50667984827ecf90f38538c9282111958a86bacc9594894ea1536cb6fac09-Screenshot_2024-11-12_at_1.39.03_PM.png]</em>.png)</p></li><li><p>If your file is properly formatted, you will see a success message upon validation:<br><em>[Image: b7f7ed43ad0e885c2203d72b8c542d0f10a5997c4399b348a905692a0d27d114-Screenshot_2024-11-12_at_2.16.58_PM.png]</em>.png)</p></li><li><p>Now that you have validated the file, click <strong>Upload file</strong> to begin uploading your cost data.</p><p><em>[Image: 3cdcb12d3c305d71eabd5f8e3b9782dfb24f0e03a76cca06fe3668b825c9e3a4-Screenshot_2024-11-12_at_1.39.49_PM.png]</em>.png)</p></li><li><p>You&#39;ll be prompted to either <strong>Upload another file</strong> if you want to add more data, or get taken back to the main File Ingestion tab view using the <strong>Go to History</strong> button.<br><em>[Image: cac5da15048f12f2ed55231fd416eb1b7e1e8b2fd34ca4a13f7ed5cd93f5aea2-Screenshot_2024-10-30_at_2.26.12_PM.png]</em>.png)</p></li><li><p>If you click <strong>Go to History</strong> and return to the File Ingestion tab, you&#39;ll notice your file is now in the table and is in the <strong>pending</strong> state. Please note that it may stay in this state for several hours while the data is being processed.</p></li><li><p>Once your data is processed, it will get included on the <a href="https://dashboard.branch.io/ads/roi-hub/analytics" target="_blank" rel="noreferrer">ROI Hub Overview page</a>.</p></li></ol><h3 id="view-file-history" tabindex="-1">View File History <a class="header-anchor" href="#view-file-history" aria-label="Permalink to &quot;View File History&quot;">​</a></h3><p>Once you have kicked off the upload process for a file, it appears in the table on the <strong>Import History</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import?section=import-history" target="_blank" rel="noreferrer">view</a>.</p><p>To learn more about the file:</p><ol><li>Click the <strong>View</strong> button in the <strong>Action</strong> column for the file you are interested in.</li><li>When you click this button, you will see file details appear in a module.<br><em>[Image: a822a8257aa856400905e031cb2f48b38611fd18391669da018456d85482f6e9-Screenshot_2024-10-30_at_5.32.00_PM.png]</em>.png)</li><li>If you click <strong>View</strong> on a file that failed during the upload process, you will see what the error was that caused the failure.<br><em>[Image: ac899af068c14b83175e31dc169fa45b357054448ba36075a50a4dcfe6208307-Screenshot_2024-10-30_at_5.36.57_PM.png]</em>.png)</li><li>You can also click <strong>Download file with errors</strong> to download a CSV file that contains all the data from your file alongside the errors that occurred when Branch tried to process it.</li></ol><h3 id="filter-uploaded-files" tabindex="-1">Filter Uploaded Files <a class="header-anchor" href="#filter-uploaded-files" aria-label="Permalink to &quot;Filter Uploaded Files&quot;">​</a></h3><p>Once you&#39;ve uploaded some files containing cost data, you can filter them by different attributes. For example, you could filter by ad partner &quot;Impact&quot; and status &quot;Success&quot; to see all the successful file uploads related to Impact. Or you could filter by ad partner &quot;All&quot; and status &quot;Failed&quot; to see all failed imports. Make sure to note the <strong>Import Type</strong> column here, which can say either <strong>File Upload</strong> or <strong>Email Importer</strong>.</p><p>You can also search for the file name if you know any part of it. Please note that this search is <strong>case-sensitive</strong>.</p><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>There are a few different errors that might occur during the upload process, which mainly have to do with formatting.</p><p>These are the errors messages you might see, as well as their corresponding meaning:</p><ul><li><strong>Required fields are missing or formatted incorrectly</strong>: When any of the three required fields (<code>date</code>, <code>campaign_name</code> or <code>cost</code>) aren’t filled in or have the wrong format.</li><li><strong>Bad datatype or formatting detected</strong>: When the data in the column doesn’t match what’s expected (e.g. a value for <code>currency</code> is in the <code>cost</code> column).</li><li><strong>Fields contain values not currently supported</strong>: This is when the <code>country</code> or <code>os</code> column has a value that doesn’t match what is expected.</li><li><strong>Required fields do not exist in data file</strong>: This is when the column names <code>date</code>, <code>campaign_name</code>, or <code>cost</code> don’t exist in the file, or there are extra columns that don’t match the <a href="./cost-data-via-file-upload.html#template">template file</a>.</li></ul>',25)])])}const f=o(i,[["render",d]]);export{u as __pageData,f as default};
